// Entradas: Resumo mensal (v_resumo_mensal_oficial) e Reconciliacao (v_reconciliacao_mensalidades)
const resumos = ($('Resumo mensal').all() || []).map(i => i.json);
const recons = ($('Reconciliacao').all() || []).map(i => i.json);

const now = new Date();
const lastMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const prevMonth = new Date(now.getFullYear(), now.getMonth() - 2, 1);
const anoAtual = lastMonth.getFullYear();
const mesAtual = lastMonth.getMonth() + 1;
const anoAnt = prevMonth.getFullYear();
const mesAnt = prevMonth.getMonth() + 1;

const resumoMes = resumos.find(r => r.ano === anoAtual && r.mes === mesAtual);
const resumoAnt = resumos.find(r => r.ano === anoAnt && r.mes === mesAnt);

const pendentes = recons.filter(r => r.confirmado_banco === false && r.data_pagamento)
  .filter(r => {
    const d = new Date(r.data_pagamento);
    return d.getFullYear() === anoAtual && (d.getMonth() + 1) === mesAtual;
  });

const mesNome = ['','Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'][mesAtual];

let context = `Mês de referência: ${mesNome}/${anoAtual}\n\n`;
if (resumoMes) {
  context += `Resumo do mês (oficial):\n- Total entradas: R$ ${Number(resumoMes.total_entradas || 0).toFixed(2)}\n- Total saídas: R$ ${Number(resumoMes.total_saidas || 0).toFixed(2)}\n- Saldo do mês: R$ ${Number(resumoMes.saldo_mes || 0).toFixed(2)}\n- Quantidade de entradas: ${resumoMes.qtd_entradas || 0}\n- Quantidade de saídas: ${resumoMes.qtd_saidas || 0}\n\n`;
}
if (resumoAnt) {
  context += `Mês anterior (${['','Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'][mesAnt]}/${anoAnt}):\n- Total entradas: R$ ${Number(resumoAnt.total_entradas || 0).toFixed(2)}\n- Saldo: R$ ${Number(resumoAnt.saldo_mes || 0).toFixed(2)}\n\n`;
}
if (pendentes.length > 0) {
  context += `Mensalidades ainda NÃO confirmadas no banco (${pendentes.length}):\n`;
  pendentes.slice(0, 30).forEach(p => {
    context += `- ${p.aluno_nome || 'N/A'} (${p.atividade_nome || 'N/A'}): R$ ${Number(p.valor || 0).toFixed(2)}, data ref. ${p.data_pagamento || 'N/A'}\n`;
  });
  if (pendentes.length > 30) context += `... e mais ${pendentes.length - 30} itens.\n`;
} else {
  context += 'Mensalidades não confirmadas no banco: nenhuma pendência listada para o mês.\n';
}

// Role + Output constraint (system)
const systemPrompt = `Você é um analista financeiro do Espaço Byla, um espaço cultural. Sua tarefa é gerar resumos executivos objetivos a partir dos dados fornecidos. Responda sempre em português brasileiro. Formato de saída obrigatório: use exatamente as seções ## Resumo, ## Números do mês, ## Inadimplência, ## Recomendações. Seja conciso. Máximo 500 palavras.`;

// Instruction + Context + CoT (user)
const userPrompt = `Analise passo a passo os dados abaixo e produza o resumo executivo do mês.\n\n[DADOS]\n${context}\n[FIM DADOS]\n\nPassos: 1) Resuma os totais e a tendência vs mês anterior; 2) Comente a situação de inadimplência se houver; 3) Dê 1 a 3 recomendações práticas. Gere o texto nas seções solicitadas.`;

return [{ json: { systemPrompt, userPrompt, reportContext: context } }];

const item = $input.first();
const body = item.json;
const content = body.choices && body.choices[0] && body.choices[0].message ? body.choices[0].message.content : (body.content || JSON.stringify(body));
return [{ json: { report: content, raw: body } }];
